                    // Remove after animation completes
                    setTimeout(() => oldEl.remove(), 200); // Match CSS transition duration
                }
            });

            // Add new elements or update existing ones
            newReversedChars.forEach((newChar, newIndex) => {
                const existingEl = oldElements[newIndex];
                const newCharWrapper = newCharElements[newIndex];

                if (existingEl) {
                    // Update existing element's text if it's different and remove exiting class
                    if (existingEl.querySelector('span').textContent !== newChar) {
                        existingEl.querySelector('span').textContent = newChar;
                        existingEl.classList.remove('exiting'); // Ensure it's not marked for removal
                        existingEl.classList.remove('active'); // Re-trigger active animation
                        // A small delay to ensure CSS transition applies after class removal
                        setTimeout(() => existingEl.classList.add('active'), 10);
                    } else if (existingEl.classList.contains('exiting')) {
                         // If it was marked for exit but now it's back, reactivate
                         existingEl.classList.remove('exiting');
                         existingEl.classList.add('active');
                    }
                } else {
                    // Append new elements
                    outputArea.appendChild(newCharWrapper);
                    // Trigger fade-in animation
                    setTimeout(() => newCharWrapper.classList.add('active'), 10);
                }
            });

            // Remove any old elements that are left over (e.g., if new string is shorter)
            while (outputArea.children.length > newReversedChars.length) {
                const lastChild = outputArea.lastChild;
                if (lastChild) {
                    lastChild.classList.add('exiting');
                    setTimeout(() => lastChild.remove(), 200);
                }
            }

            // Ensure all remaining elements are marked active if they weren't removed
            Array.from(outputArea.children).forEach(el => {
