                let isNewOrChanged = true;
                if (previousReversedChars[index] === char) {
                    isNewOrChanged = false; // Same character in the same position
                }

                if (isNewOrChanged) {
                    // Add highlight class for a brief animation
                    charWrapper.classList.add('highlight');
                    setTimeout(() => {
                        charWrapper.classList.remove('highlight');
                    }, 400); // Duration of the bounceIn animation
                }

                reversedOutput.appendChild(charWrapper);
            });

            // Update previous characters for the next input event
            previousReversedChars = currentReversedChars;
        });

        // Initialize with an empty state or a default message
        stringInput.dispatchEvent(new Event('input')); // Trigger initial render
    </script>
