    <h1>Binary Search Visualizer</h1>

    <div id="controls">
        <label for="targetInput">Target Value:</label>
        <input type="number" id="targetInput" value="42" min="1" max="100">
        <button id="startButton">Start Search</button>
        <button id="stepButton">Next Step</button>
        <button id="resetButton">Reset</button>
    </div>

    <div id="status">Enter a target and click "Start Search" to begin.</div>

    <div id="arrayContainer">
        <!-- Array boxes will be generated here by JavaScript -->
    </div>

    <script>
        const arrayContainer = document.getElementById('arrayContainer');
        const targetInput = document.getElementById('targetInput');
        const startButton = document.getElementById('startButton');
        const stepButton = document.getElementById('stepButton');
        const resetButton = document.getElementById('resetButton');
        const statusDiv = document.getElementById('status');

        // The sorted array for visualization
        const sortedArray = Array.from({ length: 25 }, (_, i) => (i + 1) * 3); // Example: [3, 6, 9, ..., 75]
        let targetValue = null;
        let low = 0;
        let high = sortedArray.length - 1;
        let mid = -1;
        let searchActive = false;
        let found = false;

        // --- Initialization and UI Setup ---

        function generateArrayBoxes() {
            arrayContainer.innerHTML = ''; // Clear previous boxes
            sortedArray.forEach((value, index) => {
                const box = document.createElement('div');
                box.classList.add('array-box');
                box.dataset.index = index; // Store original index
                box.textContent = value;
                arrayContainer.appendChild(box);
            });
        }

        function resetVisualization() {
            targetValue = null;
            low = 0;
            high = sortedArray.length - 1;
            mid = -1;
            searchActive = false;
            found = false;

            statusDiv.textContent = 'Enter a target and click "Start Search" to begin.';
            targetInput.disabled = false;
            startButton.disabled = false;
            stepButton.disabled = true;
            stepButton.classList.remove('active');
            resetButton.disabled = false; // Always enabled for full reset

            const boxes = document.querySelectorAll('.array-box');
            boxes.forEach(box => {
                box.classList.remove('in-range', 'middle', 'found', 'not-found-middle');
            });
        }

        // --- Binary Search Logic (Step-by-Step) ---

        function startSearch() {
            const inputVal = parseInt(targetInput.value);
            if (isNaN(inputVal)) {
                alert('Please enter a valid number for the target value.');
                return;
            }
            targetValue = inputVal;

            resetVisualization(); // Reset state but keep generated boxes
            searchActive = true;
            targetInput.disabled = true;
            startButton.disabled = true;
            stepButton.disabled = false;
            stepButton.classList.add('active');
            statusDiv.textContent = `Searching for ${targetValue}...`;

            highlightRange();
        }

        function highlightRange() {
            const boxes = document.querySelectorAll('.array-box');
            boxes.forEach((box, index) => {
                box.classList.remove('in-range', 'middle', 'found', 'not-found-middle');
                if (index >= low && index <= high) {
                    box.classList.add('in-range');
                }
            });
        }

        function takeStep() {
            if (!searchActive || found) return; // Don't step if not active or already found

            if (low <= high) {
                mid = Math.floor((low + high) / 2);
                const midValue = sortedArray[mid];

                // Clear previous middle highlights
                document.querySelectorAll('.array-box.middle, .array-box.not-found-middle').forEach(box => {
                    box.classList.remove('middle', 'not-found-middle');
                });

                // Highlight current middle
                const midBox = document.querySelector(`.array-box[data-index="${mid}"]`);
                if (midBox) {
                    midBox.classList.add('middle');
                }

                statusDiv.textContent = `Comparing ${targetValue} with middle element ${midValue} at index ${mid}.`;

                if (midValue === targetValue) {
                    found = true;
                    if (midBox) {
                        midBox.classList.remove('middle', 'in-range');
                        midBox.classList.add('found');
                    }
                    statusDiv.textContent = `Target ${targetValue} found at index ${mid}!`;
                    endSearch();
                } else if (midValue < targetValue) {
                    low = mid + 1;
                    statusDiv.textContent += ` Target is greater, search in right half (index ${low} to ${high}).`;
                    // Delay range highlight slightly to see middle first
                    setTimeout(highlightRange, 800);
                } else { // midValue > targetValue
                    high = mid - 1;
                    statusDiv.textContent += ` Target is smaller, search in left half (index ${low} to ${high}).`;
                    // Delay range highlight slightly to see middle first
                    setTimeout(highlightRange, 800);
                }
            } else {
                // Search range has collapsed, target not found
                if (!found) { // Double check if it wasn't found in the last step
                    statusDiv.textContent = `Target ${targetValue} not found in the array.`;
                    // If a middle element was the last one checked, mark it as not-found
                    const lastMidBox = document.querySelector(`.array-box[data-index="${mid}"]`);
                    if (lastMidBox) {
                        lastMidBox.classList.remove('middle', 'in-range');
                        lastMidBox.classList.add('not-found-middle');
                    }
                }
                endSearch();
            }
        }

        function endSearch() {
            searchActive = false;
            stepButton.disabled = true;
            stepButton.classList.remove('active');
            // Allow starting a new search
            targetInput.disabled = false;
            startButton.disabled = false;
        }

        // --- Event Listeners ---

        startButton.addEventListener('click', startSearch);
        stepButton.addEventListener('click', takeStep);
        resetButton.addEventListener('click', resetVisualization);

        // Allow pressing Enter in target input to start search
        targetInput.addEventListener('keypress', (event) => {
            if (event.key === 'Enter' && !startButton.disabled) {
                startButton.click();
            }
        });

        // Initial setup
        generateArrayBoxes();
        resetVisualization(); // Ensure initial state is clean
    </script>
</body>
</html>
