            background-color: #ffc107; /* Orange for middle element */
            border-color: #ffc107;
            transform: scale(1.1);
            box-shadow: 0 0 8px rgba(255,193,7,0.5);
        }

        .array-box.found {
            background-color: #28a745; /* Green for found target */
            color: white;
            border-color: #28a745;
            transform: scale(1.15);
            box-shadow: 0 0 10px rgba(40,167,69,0.7);
        }

        .array-box.not-found {
            background-color: #dc3545; /* Red for not found target */
            color: white;
            border-color: #dc3545;
        }

        #status {
            margin-top: 20px;
            font-size: 1.2em;
            font-weight: bold;
            padding: 10px 15px;
            border-radius: 5px;
            min-width: 200px;
            text-align: center;
        }

        #status.found-msg {
            background-color: #d4edda;
            color: #155724;
            border: 1px solid #c3e6cb;
        }

        #status.not-found-msg {
            background-color: #f8d7da;
            color: #721c24;
            border: 1px solid #f5c6cb;
