<body>
    <h1>Binary Search Visualizer</h1>

    <div class="controls">
        <label for="targetInput">Target:</label>
        <input type="number" id="targetInput" value="45">
        <button id="resetButton">Reset</button>
        <button id="stepButton">Step</button>
    </div>

    <div id="arrayContainer">
        <!-- Array boxes will be rendered here by JavaScript -->
    </div>

    <div id="status">
        Enter target and click Reset to start.
    </div>

    <script>
        const ARRAY_SIZE = 15;
        const MAX_VALUE = 100;
        let sortedArray = [];
        let low = 0;
        let high = 0;
        let target = 0;
        let found = false;
        let searchComplete = false;
        let middleElement = null;

        const arrayContainer = document.getElementById('arrayContainer');
        const targetInput = document.getElementById('targetInput');
        const resetButton = document.getElementById('resetButton');
        const stepButton = document.getElementById('stepButton');
        const statusDiv = document.getElementById('status');

        function generateSortedArray() {
            const arr = new Set(); // Use Set to ensure unique values
            while (arr.size < ARRAY_SIZE) {
                arr.add(Math.floor(Math.random() * MAX_VALUE) + 1);
            }
            return Array.from(arr).sort((a, b) => a - b);
        }

        function renderArray() {
            arrayContainer.innerHTML = '';
            sortedArray.forEach((num, index) => {
                const box = document.createElement('div');
                box.classList.add('array-box');
                box.dataset.index = index;
                box.textContent = num;
                arrayContainer.appendChild(box);
            });
        }

        function updateVisualization() {
            const boxes = document.querySelectorAll('.array-box');
            boxes.forEach((box, index) => {
                box.classList.remove('in-range', 'middle', 'found', 'not-found');

                if (searchComplete) {
                    if (found) {
                        if (parseInt(box.textContent) === target) {
                            box.classList.add('found');
                        }
                    } else {
                        // Mark the elements in the last active range as not-found if it's the final state
                        // This part is a bit tricky, if the element was never found, we just show the state after the last comparison
                        // For simplicity, we can just show the entire array as "not found" if the search completed without finding
                        // Or, better, just leave them as default unless they were the target.
                        // For now, let's keep it clean and only highlight the found element.
                    }
                    return; // No further range/middle highlighting if search is complete
                }

                if (index >= low && index <= high) {
                    box.classList.add('in-range');
                }

                if (index === middleElement) {
                    box.classList.add('middle');
                }
            });
        }

        function resetSearch() {
            sortedArray = generateSortedArray();
            target = parseInt(targetInput.value);
            low = 0;
            high = sortedArray.length - 1;
            found = false;
            searchComplete = false;
            middleElement = null;

            renderArray();
            updateVisualization();
            statusDiv.textContent = 'Ready to search. Click Step.';
            statusDiv.className = ''; // Clear status classes
            stepButton.disabled = false;
        }

        function stepSearch() {
            if (searchComplete) {
                statusDiv.textContent = found ? `Target ${target} found!` : `Target ${target} not found.`;
                statusDiv.classList.add(found ? 'found-msg' : 'not-found-msg');
                stepButton.disabled = true;
                return;
            }

            if (low > high) {
                searchComplete = true;
                found = false;
                statusDiv.textContent = `Target ${target} not found in the array.`;
                statusDiv.classList.add('not-found-msg');
                updateVisualization(); // Final update to clear middle/range
                stepButton.disabled = true;
                return;
            }

            middleElement = Math.floor((low + high) / 2);
            const midValue = sortedArray[middleElement];

            updateVisualization(); // Update before comparison for current step's highlight

            // Small delay to make the highlight visible before status changes quickly
            setTimeout(() => {
                if (midValue === target) {
                    found = true;
                    searchComplete = true;
                    statusDiv.textContent = `Target ${target} found at index ${middleElement}!`;
                    statusDiv.classList.add('found-msg');
                    // Mark the found element
                    const foundBox = document.querySelector(`.array-box[data-index="${middleElement}"]`);
                    if (foundBox) {
                        foundBox.classList.remove('in-range', 'middle'); // Remove previous highlights
                        foundBox.classList.add('found');
                    }
                    stepButton.disabled = true;
                } else if (midValue < target) {
                    low = middleElement + 1;
                    statusDiv.textContent = `${midValue} < ${target}. Search in right half. (low=${low}, high=${high})`;
                } else { // midValue > target
                    high = middleElement - 1;
                    statusDiv.textContent = `${midValue} > ${target}. Search in left half. (low=${low}, high=${high})`;
                }

                // If search is complete after this step, ensure final visualization is correct
                if (searchComplete) {
                    updateVisualization();
                }
            }, 500); // Half-second delay
        }

        // Event Listeners
        resetButton.addEventListener('click', resetSearch);
        stepButton.addEventListener('click', stepSearch);
        targetInput.addEventListener('change', () => {
            // Re-render array if target changes to ensure a fresh start
            resetSearch();
        });

        // Initial setup
        resetSearch();
    </script>
</body>
</html>
