                if (searchInProgress && !searchFinished) {
                    // Highlight active range
                    if (index >= low && index <= high) {
                        box.classList.add('active-range');
                    }
                    // Highlight middle element
                    if (index === mid) {
                        box.classList.add('middle-element');
                    }
