            if (isNaN(target)) {
                statusMessage.textContent = 'Please enter a valid number as target.';
                statusMessage.className = 'status-message not-found';
                return;
            }

            resetSearchState(); // Reset state before starting a new search
            searchInProgress = true;
            searchFinished = false;
            low = 0;
            high = array.length - 1;
            mid = -1; // Reset mid for the first step

