        </div>
        <div class="control-group">
            <label for="insertTailValue">Value:</label>
            <input type="number" id="insertTailValue" placeholder="e.g., 20">
            <button onclick="insertAtTail()">Insert at Tail</button>
        </div>
        <div class="control-group">
            <label for="deleteValue">Value:</label>
            <input type="number" id="deleteValue" placeholder="e.g., 15">
            <button onclick="deleteByValue()">Delete by Value</button>
        </div>
        <div class="control-group">
            <label for="searchValue">Value:</label>
            <input type="number" id="searchValue" placeholder="e.g., 25">
            <button onclick="searchList()">Search</button>
        </div>
        <button onclick="clearList()" style="background-color: #e74c3c;">Clear List</button>
    </div>

    <div id="listContainer" class="list-container">
        <div class="empty-list-message" id="emptyMessage">List is empty. Add some nodes!</div>
    </div>

    <div id="feedbackMessage" class="feedback-message"></div>

    <script>
        class Node {
            constructor(value) {
                this.value = value;
                this.next = null;
            }
        }

        class LinkedList {
            constructor() {
                this.head = null;
                this.tail = null;
                this.size = 0;
            }

            insertAtHead(value) {
                const newNode = new Node(value);
                if (this.head === null) {
                    this.head = newNode;
                    this.tail = newNode;
                } else {
                    newNode.next = this.head;
                    this.head = newNode;
                }
                this.size++;
            }

            insertAtTail(value) {
                const newNode = new Node(value);
                if (this.tail === null) {
                    this.head = newNode;
                    this.tail = newNode;
                } else {
                    this.tail.next = newNode;
                    this.tail = newNode;
                }
                this.size++;
            }

            deleteByValue(value) {
                if (this.head === null) {
                    return false; // List is empty
                }

                // If head node is the one to be deleted
                if (this.head.value === value) {
                    if (this.head === this.tail) { // Only one node in list
                        this.head = null;
                        this.tail = null;
                    } else {
                        this.head = this.head.next;
                    }
                    this.size--;
                    return true;
                }

                let current = this.head;
                let prev = null;
                while (current !== null && current.value !== value) {
                    prev = current;
                    current = current.next;
                }

                if (current === null) {
                    return false; // Value not found
                }

                // Value found, delete it
                prev.next = current.next;
                if (current === this.tail) { // If deleting the tail node
                    this.tail = prev;
                }
                this.size--;
                return true;
            }

            search(value) {
                let current = this.head;
                let index = 0;
                while (current !== null) {
                    if (current.value === value) {
                        return index; // Return the index if found
                    }
                    current = current.next;
                    index++;
                }
                return -1; // Not found
            }

            isEmpty() {
                return this.head === null;
            }

            clear() {
                this.head = null;
                this.tail = null;
                this.size = 0;
            }
        }

        const linkedList = new LinkedList();
        const listContainer = document.getElementById('listContainer');
        const emptyMessage = document.getElementById('emptyMessage');
        const feedbackMessage = document.getElementById('feedbackMessage');

        function displayFeedback(message, type) {
            feedbackMessage.textContent = message;
            feedbackMessage.className = `feedback-message show ${type}`;
            setTimeout(() => {
                feedbackMessage.classList.remove('show');
            }, 3000);
        }

        function renderList() {
            listContainer.innerHTML = ''; // Clear existing visualization
            emptyMessage.style.display = linkedList.isEmpty() ? 'block' : 'none';

            if (linkedList.isEmpty()) {
                listContainer.appendChild(emptyMessage);
                return;
            }

            let current = linkedList.head;
            let firstNodeElement = null;
            let lastNodeElement = null;

            while (current !== null) {
                const nodeWrapper = document.createElement('div');
                nodeWrapper.classList.add('node-wrapper');

                const nodeElement = document.createElement('div');
                nodeElement.classList.add('node');
                nodeElement.textContent = current.value;
                nodeElement.dataset.value = current.value; // Store value for search/delete

                nodeWrapper.appendChild(nodeElement);

                if (current.next !== null) {
                    const arrowElement = document.createElement('div');
                    arrowElement.classList.add('arrow');
                    nodeWrapper.appendChild(arrowElement);
                } else {
                    // This is the last node, add a "null" pointer box
                    const nullPointerElement = document.createElement('div');
                    nullPointerElement.classList.add('null-pointer');
                    nullPointerElement.textContent = 'NULL';
                    const arrowElement = document.createElement('div');
                    arrowElement.classList.add('arrow');
                    nodeWrapper.appendChild(arrowElement);
                    nodeWrapper.appendChild(nullPointerElement);
                }

                listContainer.appendChild(nodeWrapper);

                if (!firstNodeElement) firstNodeElement = nodeElement;
                lastNodeElement = nodeElement; // Keep track of the last rendered node

                current = current.next;
            }

            // Add HEAD and TAIL labels
            if (firstNodeElement) {
                const headLabel = document.createElement('div');
                headLabel.classList.add('head-label');
                headLabel.textContent = 'HEAD';
                headLabel.style.left = `${firstNodeElement.offsetLeft + firstNodeElement.offsetWidth / 2}px`;
                listContainer.appendChild(headLabel);
            }
            if (lastNodeElement && linkedList.head !== linkedList.tail) { // Only show tail if not the same as head
                const tailLabel = document.createElement('div');
                tailLabel.classList.add('tail-label');
                tailLabel.textContent = 'TAIL';
                tailLabel.style.left = `${lastNodeElement.offsetLeft + lastNodeElement.offsetWidth / 2}px`;
                listContainer.appendChild(tailLabel);
            } else if (lastNodeElement && linkedList.head === linkedList.tail) { // If only one node
                 const tailLabel = document.createElement('div');
                tailLabel.classList.add('tail-label');
                tailLabel.textContent = 'TAIL';
                tailLabel.style.left = `${lastNodeElement.offsetLeft + lastNodeElement.offsetWidth / 2}px`;
                listContainer.appendChild(tailLabel);
            }
        }

        function getNodeValue(id) {
            const input = document.getElementById(id);
            const value = parseInt(input.value);
            if (isNaN(value)) {
                displayFeedback('Please enter a valid number.', 'error');
                return null;
            }
            input.value = ''; // Clear input after use
            return value;
        }

        function insertAtHead() {
            const value = getNodeValue('insertHeadValue');
            if (value !== null) {
                linkedList.insertAtHead(value);
                renderList();
                displayFeedback(`Inserted ${value} at head.`, 'success');
            }
        }

        function insertAtTail() {
            const value = getNodeValue('insertTailValue');
            if (value !== null) {
                linkedList.insertAtTail(value);
                renderList();
                displayFeedback(`Inserted ${value} at tail.`, 'success');
            }
        }

        function deleteByValue() {
            const value = getNodeValue('deleteValue');
            if (value !== null) {
                const success = linkedList.deleteByValue(value);
                if (success) {
                    renderList();
                    displayFeedback(`Deleted ${value}.`, 'success');
                } else {
                    displayFeedback(`${value} not found in the list.`, 'error');
                }
            }
        }

        function searchList() {
            const value = getNodeValue('searchValue');
            if (value !== null) {
                // Remove existing highlights first
                document.querySelectorAll('.node.highlight').forEach(node => {
                    node.classList.remove('highlight');
                });

                const index = linkedList.search(value);
                if (index !== -1) {
                    const nodes = listContainer.querySelectorAll('.node');
                    if (nodes[index]) {
                        nodes[index].classList.add('highlight');
                        displayFeedback(`Found ${value} at index ${index}.`, 'success');
                        // Scroll to the found node if it's out of view
                        nodes[index].scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
                    }
                } else {
                    displayFeedback(`${value} not found in the list.`, 'error');
                }
            }
        }

        function clearList() {
            linkedList.clear();
            renderList();
            displayFeedback('List cleared.', 'success');
        }

        // Initial render
        renderList();
    </script>
</body>
</html>
