                linkedList.insertAtHead(value);
                input.value = ''; // Clear input
            } else {
                alert("Please enter a valid number for insert at head.");
            }
        }

        function insertAtTail() {
            const input = document.getElementById('insertTailValue');
            const value = parseInt(input.value);
            if (!isNaN(value)) {
                linkedList.insertAtTail(value);
                input.value = ''; // Clear input
            } else {
                alert("Please enter a valid number for insert at tail.");
            }
        }

        function deleteByValue() {
            const input = document.getElementById('deleteValue');
            const value = parseInt(input.value);
            if (!isNaN(value)) {
                linkedList.deleteByValue(value);
                input.value = ''; // Clear input
            } else {
                alert("Please enter a valid number for delete by value.");
            }
        }

        async function searchByValue() {
            const input = document.getElementById('searchValue');
            const value = parseInt(input.value);
            if (!isNaN(value)) {
                const foundNode = linkedList.search(value);
                if (foundNode) {
                    linkedList.render(foundNode); // Render with the found node highlighted
                    await new Promise(resolve => setTimeout(resolve, 1500)); // Keep highlighted for 1.5 seconds
                    linkedList.render(); // Re-render to remove highlight
                } else {
                    alert(`Value ${value} not found in the list.`);
                    linkedList.render(); // Ensure any previous highlight is removed
                }
                input.value = ''; // Clear input
            } else {
                alert("Please enter a valid number for search by value.");
            }
        }

        // Initial render for empty list message
        linkedList.render();
    </script>
