    <script>
        class Node {
            constructor(value) {
                this.value = value;
                this.next = null;
            }
        }

        class LinkedList {
            constructor() {
                this.head = null;
            }

            insertAtHead(value) {
                const newNode = new Node(value);
                newNode.next = this.head;
                this.head = newNode;
                this.render();
                this.animateNode(newNode.value, 'inserting');
            }

            insertAtTail(value) {
                const newNode = new Node(value);
                if (!this.head) {
                    this.head = newNode;
                } else {
                    let current = this.head;
                    while (current.next) {
                        current = current.next;
                    }
                    current.next = newNode;
                }
                this.render();
                this.animateNode(newNode.value, 'inserting');
            }

            deleteNode(value) {
                if (!this.head) {
                    alert("List is empty. Cannot delete.");
                    return;
                }

                // If head needs to be removed
                if (this.head.value === value) {
                    this.animateNode(this.head.value, 'deleting', () => {
                        this.head = this.head.next;
                        this.render();
                    });
                    return;
                }

                let current = this.head;
                let prev = null;

                while (current && current.value !== value) {
                    prev = current;
                    current = current.next;
                }

                if (current) { // Node found
                    this.animateNode(current.value, 'deleting', () => {
                        prev.next = current.next;
                        this.render();
                    });
                } else {
                    alert(`Node with value ${value} not found.`);
                }
            }

            searchNode(value) {
                if (!this.head) {
                    alert("List is empty. Cannot search.");
                    return null;
                }

                let current = this.head;
                let foundNode = null;
                const searchPath = [];

                while (current) {
                    searchPath.push(current.value);
                    if (current.value === value) {
                        foundNode = current;
                        break;
                    }
                    current = current.next;
                }

                this.visualizeSearch(searchPath, value, foundNode);
                return foundNode;
            }

            // --- Visualization Logic ---
            render() {
                const container = document.getElementById('listContainer');
                container.innerHTML = ''; // Clear existing visualization

                if (!this.head) {
                    container.innerHTML = '<div id="emptyMessage" class="empty-list-message">List is empty. Add some nodes!</div>';
                    return;
                }

                // Remove empty message if it exists
                const emptyMessage = document.getElementById('emptyMessage');
                if (emptyMessage) {
                    emptyMessage.remove();
                }

                let current = this.head;
                while (current) {
                    const nodeDiv = document.createElement('div');
                    nodeDiv.classList.add('node');
                    nodeDiv.setAttribute('data-value', current.value); // Store value for easy lookup

                    const nodeBox = document.createElement('div');
                    nodeBox.classList.add('node-box');
                    nodeBox.textContent = current.value;
                    nodeDiv.appendChild(nodeBox);

                    if (current.next) {
                        const arrowDiv = document.createElement('div');
                        arrowDiv.classList.add('arrow');
                        nodeDiv.appendChild(arrowDiv);
                    }

                    container.appendChild(nodeDiv);
                    current = current.next;
                }
            }

            animateNode(value, type, callback = () => {}) {
                const nodeBox = document.querySelector(`.node[data-value="${value}"] .node-box`);
                if (nodeBox) {
                    nodeBox.classList.add(type);
                    setTimeout(() => {
                        nodeBox.classList.remove(type);
                        callback(); // Execute callback after animation
                    }, 500); // Animation duration
                } else {
                    callback(); // If node not found (e.g., deleted head before animation), still call callback
                }
            }

            async visualizeSearch(path, targetValue, foundNode) {
                const container = document.getElementById('listContainer');
                const allNodes = container.querySelectorAll('.node-box');

                // Clear any previous highlights
                allNodes.forEach(node => node.classList.remove('highlight'));

                if (!foundNode) {
                    alert(`Value ${targetValue} not found in the list.`);
                    return;
                }

                for (let i = 0; i < path.length; i++) {
                    const nodeValue = path[i];
                    const currentNodeBox = document.querySelector(`.node[data-value="${nodeValue}"] .node-box`);

                    if (currentNodeBox) {
                        currentNodeBox.style.backgroundColor = '#add8e6'; // Light blue for visited
                        await new Promise(resolve => setTimeout(resolve, 300)); // Pause for visualization

                        if (nodeValue === targetValue) {
                            currentNodeBox.classList.add('highlight'); // Highlight if found
                            alert(`Value ${targetValue} found!`);
                            await new Promise(resolve => setTimeout(resolve, 1000)); // Keep highlighted for a bit
                            currentNodeBox.classList.remove('highlight');
                            currentNodeBox.style.backgroundColor = ''; // Reset color
                            break;
                        } else {
                             currentNodeBox.style.backgroundColor = ''; // Reset color after visiting
                        }
                    }
                }
                 // Ensure all nodes reset their background color
                allNodes.forEach(node => {
                    node.classList.remove('highlight');
                    node.style.backgroundColor = '';
                });
            }
        }

        const list = new LinkedList();

        function insertAtHead() {
            const value = parseInt(document.getElementById('insertHeadValue').value);
            if (!isNaN(value)) {
                list.insertAtHead(value);
                document.getElementById('insertHeadValue').value = '';
            } else {
                alert("Please enter a valid number for insert at head.");
            }
        }

        function insertAtTail() {
            const value = parseInt(document.getElementById('insertTailValue').value);
            if (!isNaN(value)) {
                list.insertAtTail(value);
                document.getElementById('insertTailValue').value = '';
            } else {
                alert("Please enter a valid number for insert at tail.");
            }
        }

        function deleteNode() {
            const value = parseInt(document.getElementById('deleteValue').value);
            if (!isNaN(value)) {
                list.deleteNode(value);
                document.getElementById('deleteValue').value = '';
            } else {
                alert("Please enter a valid number to delete.");
            }
        }

        function searchNode() {
            const value = parseInt(document.getElementById('searchValue').value);
            if (!isNaN(value)) {
                list.searchNode(value);
                document.getElementById('searchValue').value = '';
            } else {
                alert("Please enter a valid number to search.");
            }
        }

        // Initial render for empty list
        list.render();
    </script>
</body>
</html>
