            /**
             * Parses CSV text into a 2D array of strings.
             * Handles quoted fields, commas within quotes, and escaped quotes.
             * @param {string} csvString The raw CSV text.
             * @returns {string[][]} A 2D array representing the CSV data.
             */
            function parseCSV(csvString) {
                const lines = csvString.split(/\r?\n/);
                const data = [];

                lines.forEach(line => {
                    if (!line.trim()) return; // Skip empty lines

                    const row = [];
                    let inQuote = false;
                    let field = '';

                    for (let i = 0; i < line.length; i++) {
                        const char = line[i];

                        if (char === '"') {
                            if (inQuote && line[i + 1] === '"') {
                                // Escaped quote: "" becomes "
                                field += '"';
                                i++; // Skip the next quote
                            } else {
                                // Start or end of a quote
                                inQuote = !inQuote;
                            }
                        } else if (char === ',' && !inQuote) {
                            // End of a field
                            row.push(field.trim());
                            field = '';
                        } else {
                            // Regular character
                            field += char;
                        }
                    }
                    // Push the last field of the row
                    row.push(field.trim());
                    data.push(row);
                });

                return data;
            }

