                if (existingError) {
                    existingError.remove();
                }

                // Determine the maximum number of columns for consistent table structure
                const maxCols = data.reduce((max, row) => Math.max(max, row.length), 0);

                // Create header row (assuming first row is header, or generate generic if not enough rows)
                const headerRow = document.createElement('tr');
                // If there's at least one row, use its content for headers.
                // Otherwise, generate generic "Column X" headers.
                const headers = data.length > 0 ? data[0] : Array.from({ length: maxCols }, (_, i) => `Column ${i + 1}`);

                // If the first row is used as headers, remove it from the data for the body
                const dataRows = data.length > 0 ? data.slice(1) : [];

                // Create header cells
                headers.forEach(headerText => {
                    const th = document.createElement('th');
                    th.textContent = headerText;
                    headerRow.appendChild(th);
                });
                tableHead.appendChild(headerRow);

                // Fill in any missing header cells if subsequent rows have more columns
                while (headerRow.children.length < maxCols) {
                    const th = document.createElement('th');
                    th.textContent = `Column ${headerRow.children.length + 1}`;
                    headerRow.appendChild(th);
                }


                // Create data rows
                dataRows.forEach(rowData => {
                    const tr = document.createElement('tr');
                    // Ensure each row has 'maxCols' cells for consistent structure
                    for (let i = 0; i < maxCols; i++) {
