        <div class="control-group">
            <input type="number" id="searchValue" placeholder="Value">
            <button class="search" onclick="searchList()">Search</button>
        </div>
    </div>

    <div class="visualization-container" id="visualizationContainer">
        <p class="empty-list-message" id="emptyListMessage">List is empty. Add some nodes!</p>
        <svg id="arrowSvg">
            <defs>
                <marker id="arrowhead" viewBox="0 0 10 10" refX="8" refY="5" markerWidth="6" markerHeight="6" orient="auto-start-reverse">
                    <path d="M 0 0 L 10 5 L 0 10 z" />
                </marker>
            </defs>
        </svg>
    </div>

    <script>
        class Node {
            constructor(value) {
                this.value = value;
                this.next = null;
                this.element = null; // Reference to the DOM element for this node
            }
        }

        let head = null;
        const visualizationContainer = document.getElementById('visualizationContainer');
        const arrowSvg = document.getElementById('arrowSvg');
        const emptyListMessage = document.getElementById('emptyListMessage');
        let animationTimeout; // For managing search/highlighting timeouts

        // --- Helper Functions ---

        function updateEmptyListMessage() {
            emptyListMessage.style.display = head === null ? 'block' : 'none';
        }

        function clearHighlights() {
            document.querySelectorAll('.node.highlight, .node.found, .node.deleted').forEach(node => {
                node.classList.remove('highlight', 'found', 'deleted');
            });
            document.querySelectorAll('.arrow.highlight, .arrow.found').forEach(arrow => {
                arrow.classList.remove('highlight', 'found');
            });
            if (animationTimeout) {
                clearTimeout(animationTimeout);
                animationTimeout = null;
            }
        }

        function createNodeElement(node) {
            const nodeElement = document.createElement('div');
            nodeElement.classList.add('node');
            nodeElement.id = `node-${node.value}-${Date.now()}`; // Unique ID
            nodeElement.innerHTML = `
                <div class="node-value">${node.value}</div>
                <div class="node-pointer">NEXT</div>
            `;
            node.element = nodeElement; // Store reference to DOM element
            return nodeElement;
        }

        function redrawArrows() {
            // Clear existing arrows
            arrowSvg.querySelectorAll('path.arrow').forEach(arrow => arrow.remove());

            if (!head) return;

            let current = head;
            let prevNodeElement = null;

            // Recalculate container's scroll width to ensure all nodes are visible
            // This is important if nodes are added dynamically and the container needs to expand
            // For this setup, flexbox handles the layout, but we need to ensure SVG covers it.
            const containerRect = visualizationContainer.getBoundingClientRect();
            arrowSvg.setAttribute('width', containerRect.width);
            arrowSvg.setAttribute('height', containerRect.height);


            while (current && current.next) {
                const startRect = current.element.getBoundingClientRect();
                const endRect = current.next.element.getBoundingClientRect();

                // Calculate positions relative to the SVG container
                const containerLeft = visualizationContainer.scrollLeft + visualizationContainer.getBoundingClientRect().left;
                const containerTop = visualizationContainer.scrollTop + visualizationContainer.getBoundingClientRect().top;


                // Start point: right edge of the current node, vertically centered
                const startX = startRect.right - containerLeft;
                const startY = startRect.top + startRect.height / 2 - containerTop;

                // End point: left edge of the next node, vertically centered
                // We subtract a bit from endX to make sure the arrowhead doesn't overlap the node
                const endX = endRect.left - containerLeft - 10; // Adjust for arrowhead
                const endY = endRect.top + endRect.height / 2 - containerTop;

                const path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
                path.classList.add('arrow');
                path.setAttribute('data-from', current.element.id);
                path.setAttribute('data-to', current.next.element.id);

                // For a straight arrow: M startX startY L endX endY
                // For a slight curve, or to ensure it doesn't clip other nodes:
                // We can use a simple horizontal line with a small segment to the node
                const midX = startX + (endX - startX) * 0.5; // Midpoint for a gentle curve
                path.setAttribute('d', `M ${startX} ${startY} H ${midX} L ${endX} ${endY}`);
                // Simplified: M ${startX} ${startY} L ${endX} ${endY}
                arrowSvg.appendChild(path);

                current = current.next;
            }
        }

        // Debounce redrawArrows to prevent excessive calls during rapid operations
        let redrawTimeout;
        function debouncedRedrawArrows() {
            clearTimeout(redrawTimeout);
            redrawTimeout = setTimeout(redrawArrows, 50); // Adjust delay as needed
        }

        // --- Linked List Operations ---

        function insertAtHead() {
            clearHighlights();
            const value = parseInt(document.getElementById('insertValue').value);
            if (isNaN(value)) {
                alert('Please enter a valid number for insertion.');
                return;
            }

            const newNode = new Node(value);
            const newNodeElement = createNodeElement(newNode);

            if (head) {
                // Insert at the beginning of the container
                visualizationContainer.insertBefore(newNodeElement, head.element);
            } else {
                visualizationContainer.appendChild(newNodeElement);
            }

            newNode.next = head;
            head = newNode;

            newNodeElement.classList.add('highlight');
            setTimeout(() => newNodeElement.classList.remove('highlight'), 500);

            updateEmptyListMessage();
            debouncedRedrawArrows();
        }

        function insertAtTail() {
            clearHighlights();
            const value = parseInt(document.getElementById('insertValue').value);
            if (isNaN(value)) {
                alert('Please enter a valid number for insertion.');
                return;
            }

            const newNode = new Node(value);
            const newNodeElement = createNodeElement(newNode);

            if (!head) {
                head = newNode;
                visualizationContainer.appendChild(newNodeElement);
            } else {
                let current = head;
                while (current.next) {
                    current = current.next;
                }
                current.next = newNode;
                visualizationContainer.appendChild(newNodeElement);
            }

            newNodeElement.classList.add('highlight');
            setTimeout(() => newNodeElement.classList.remove('highlight'), 500);

            updateEmptyListMessage();
            debouncedRedrawArrows();
        }

        async function deleteByValue() {
            clearHighlights();
            const valueToDelete = parseInt(document.getElementById('deleteValue').value);
            if (isNaN(valueToDelete)) {
                alert('Please enter a valid number for deletion.');
                return;
            }
            if (!head) {
                alert('List is empty. Nothing to delete!');
                return;
            }

            let current = head;
            let prev = null;
            let found = false;

            while (current) {
                current.element.classList.add('highlight');
                // Highlight the arrow pointing to current, if it's not the head
                if (prev) {
                    const prevArrow = arrowSvg.querySelector(`.arrow[data-from="${prev.element.id}"][data-to="${current.element.id}"]`);
                    if (prevArrow) prevArrow.classList.add('highlight');
                }
                await new Promise(resolve => setTimeout(resolve, 300)); // Animation delay

                if (current.value === valueToDelete) {
                    current.element.classList.add('deleted'); // Mark for deletion visually
                    found = true;
                    await new Promise(resolve => setTimeout(resolve, 500)); // Show deletion mark

                    if (prev === null) { // Deleting head
                        head = current.next;
                    } else {
                        prev.next = current.next;
                    }

                    // Remove from DOM
                    current.element.remove();
                    break; // Only delete first occurrence
                } else {
                    current.element.classList.remove('highlight');
                    if (prev) {
                        const prevArrow = arrowSvg.querySelector(`.arrow[data-from="${prev.element.id}"][data-to="${current.element.id}"]`);
                        if (prevArrow) prevArrow.classList.remove('highlight');
                    }
                }
                prev = current;
                current = current.next;
            }

            if (!found) {
                alert(`Value ${valueToDelete} not found in the list.`);
            }

            clearHighlights(); // Clear any remaining highlights
            updateEmptyListMessage();
            debouncedRedrawArrows();
        }

        async function searchList() {
            clearHighlights();
            const valueToSearch = parseInt(document.getElementById('searchValue').value);
            if (isNaN(valueToSearch)) {
                alert('Please enter a valid number for search.');
                return;
            }
            if (!head) {
                alert('List is empty. Nothing to search!');
                return;
            }

            let current = head;
            let found = false;
            let delay = 300; // Milliseconds for each step

            while (current) {
                current.element.classList.add('highlight');

                // Highlight the arrow pointing to current, if it's not the head
                if (current !== head) {
                    let prev = head;
                    while (prev && prev.next !== current) {
                        prev = prev.next;
                    }
                    if (prev) {
                        const prevArrow = arrowSvg.querySelector(`.arrow[data-from="${prev.element.id}"][data-to="${current.element.id}"]`);
                        if (prevArrow) prevArrow.classList.add('highlight');
                    }
                }

                await new Promise(resolve => animationTimeout = setTimeout(resolve, delay));

                if (current.value === valueToSearch) {
                    current.element.classList.add('found');
                    if (current !== head) {
                         let prev = head;
                        while (prev && prev.next !== current) {
                            prev = prev.next;
                        }
                        if (prev) {
                            const prevArrow = arrowSvg.querySelector(`.arrow[data-from="${prev.element.id}"][data-to="${current.element.id}"]`);
                            if (prevArrow) prevArrow.classList.add('found');
                        }
                    }
                    found = true;
                    break; // Found the value, stop search
                } else {
                    current.element.classList.remove('highlight');
                    if (current !== head) {
                        let prev = head;
                        while (prev && prev.next !== current) {
                            prev = prev.next;
                        }
                        if (prev) {
                            const prevArrow = arrowSvg.querySelector(`.arrow[data-from="${prev.element.id}"][data-to="${current.element.id}"]`);
                            if (prevArrow) prevArrow.classList.remove('highlight');
                        }
                    }
                }
                current = current.next;
            }

            if (!found) {
                alert(`Value ${valueToSearch} not found.`);
            }

            // Keep "found" highlight, clear others after a delay
            animationTimeout = setTimeout(clearHighlights, found ? 2000 : 500);
        }

        // --- Event Listeners and Initial Setup ---

        // Recalculate arrows on window resize
        window.addEventListener('resize', debouncedRedrawArrows);
        // Also recalculate if the container's scroll changes (though nodes are horizontally laid out)
        visualizationContainer.addEventListener('scroll', debouncedRedrawArrows);

        // Initial render
        updateEmptyListMessage();
        debouncedRedrawArrows(); // Initial call to set up SVG size

        // Add some initial nodes for demonstration
        setTimeout(() => {
            document.getElementById('insertValue').value = 10; insertAtHead();
            setTimeout(() => {
                document.getElementById('insertValue').value = 20; insertAtTail();
                setTimeout(() => {
                    document.getElementById('insertValue').value = 5; insertAtHead();
                    setTimeout(() => {
                        document.getElementById('insertValue').value = 30; insertAtTail();
                    }, 200);
                }, 200);
            }, 200);
        }, 500); // Small delay for initial demo sequence
    </script>
</body>
</html>
```

### How it Addresses Your Requirements:

1.  **Single Self-Contained HTML File:** All HTML, CSS, and JavaScript are embedded.
2.  **Actual Working Node Boxes:**
    *   Each node is a `div` element with distinct styling.
    *   They are laid out horizontally using `display: flex` on the `visualization-container`.
    *   Each node has a value and a "NEXT" pointer label.
3.  **Arrows Pointing to the Next Node:**
    *   An `<svg>` element is absolutely positioned over the `visualization-container`.
    *   JavaScript dynamically creates `<path>` elements within the SVG.
    *   The `redrawArrows()` function calculates the exact coordinates for each arrow's start (right-middle of current node) and end (left-middle of next node).
    *   A `<marker>` element (`#arrowhead`) is defined in SVG `defs` to create actual arrowheads.
    *   The `debouncedRedrawArrows()` ensures arrows are updated efficiently on node changes or window resizing.
4.  **Controls for Insert, Delete, Search:**
    *   Input fields for values and dedicated buttons for "Insert Head," "Insert Tail," "Delete By Value," and "Search."
    *   Clear and intuitive layout for controls.
5.  **Visual Highlighting:**
    *   **`highlight` class:** Temporarily applied to nodes and arrows during traversal (e.g., in `searchList`, `deleteByValue`).
    *   **`found` class:** Applied to the target node and its incoming arrow when a search is successful.
    *   **`deleted` class:** Applied to a node just before it's removed from the DOM, providing a visual cue of its impending deletion.
    *   `clearHighlights()` function ensures previous highlights are removed before a new operation starts.
    *   `async`/`await` and `setTimeout` are used to introduce delays for step-by-step animation during search and delete, making the process visually understandable.
6.  **Handle Empty List Case Properly:**
    *   An `empty-list-message` paragraph is displayed when `head` is `null`.
    *   `updateEmptyListMessage()` toggles its visibility.
    *   Operations like delete and search explicitly check for an empty list and provide alerts.
7.  **Robustness and Edge Cases:**
    *   **First node insertion:** Handled correctly for both head and tail (they are the same initially).
    *   **Deleting the head node:** The `head` pointer is updated.
    *   **Deleting the last node:** The `next` pointer of the previous node is set to `null`.
    *   **Deleting a middle node:** The `next` pointer of the previous node bypasses the deleted node.
    *   **Searching for non-existent values:** Alerts the user.
    *   **Input validation:** Checks for `isNaN` for number inputs.
    *   **Responsive Design:** Basic media queries are included for better display on smaller screens.
    *   **`z-index` management:** Ensures nodes appear above arrows, and arrows above the container background.
    *   **`pointer-events: none` on SVG:** Allows interaction with underlying HTML elements even when SVG is overlaid.

### To Use:

1.  Save the entire code block above as an `.html` file (e.g., `linked_list_visualizer.html`).
2.  Open the file in any modern web browser.

You'll see an initial list populated, and you can then use the controls to interact with it. Enjoy the visualization!

