                            <td>Paste CSV and click 'Parse'</td>
                        </tr>
                    </tbody>
                </table>
            </div>
        </div>
    </div>

    <script>
        document.getElementById('parseButton').addEventListener('click', parseCSV);

        function parseCSV() {
            const csvText = document.getElementById('csvInput').value;
            const outputTable = document.getElementById('outputTable');
            outputTable.innerHTML = ''; // Clear previous table content

            if (!csvText.trim()) {
                outputTable.innerHTML = '<thead><tr><th>No data</th></tr></thead><tbody><tr><td>Please paste some CSV data.</td></tr></tbody>';
                return;
            }

            try {
                const parsedData = parseCSVString(csvText);

                if (parsedData.length === 0) {
                    outputTable.innerHTML = '<thead><tr><th>No data</th></tr></thead><tbody><tr><td>No valid CSV rows found.</td></tr></tbody>';
                    return;
                }

                // Determine max columns for consistent table structure
                const maxCols = parsedData.reduce((max, row) => Math.max(max, row.length), 0);

                // Create table header (using first row as headers, or generic if only one row)
                const thead = document.createElement('thead');
                const headerRow = document.createElement('tr');
                const headers = parsedData[0]; // Assume first row is headers

                for (let i = 0; i < maxCols; i++) {
                    const th = document.createElement('th');
                    th.textContent = headers[i] || `Column ${i + 1}`; // Use header or generic name
                    headerRow.appendChild(th);
                }
                thead.appendChild(headerRow);
                outputTable.appendChild(thead);

                // Create table body
                const tbody = document.createElement('tbody');
                // Start from the second row for data, if there's more than one row
                const dataRows = parsedData.slice(parsedData.length > 1 ? 1 : 0);

                // If only one row was provided, and we used it as headers, and it has data,
                // we should still display that single row's data.
                if (parsedData.length === 1 && parsedData[0].length > 0) {
                    const tr = document.createElement('tr');
                    parsedData[0].forEach(cellData => {
                        const td = document.createElement('td');
                        td.textContent = cellData;
                        tr.appendChild(td);
                    });
                    // Fill missing cells if this single row has fewer than maxCols
                    for (let i = parsedData[0].length; i < maxCols; i++) {
                        const td = document.createElement('td');
                        td.textContent = '';
                        tr.appendChild(td);
                    }
                    tbody.appendChild(tr);
                } else {
                    dataRows.forEach(rowData => {
                        const tr = document.createElement('tr');
                        for (let i = 0; i < maxCols; i++) {
                            const td = document.createElement('td');
                            td.textContent = rowData[i] || ''; // Fill missing cells with empty string
                            tr.appendChild(td);
                        }
                        tbody.appendChild(tr);
                    });
                }
                outputTable.appendChild(tbody);

            } catch (error) {
                console.error("CSV Parsing Error:", error);
                outputTable.innerHTML = `<thead><tr><th>Error</th></tr></thead><tbody><tr><td>Failed to parse CSV: ${error.message}. Please check your input.</td></tr></tbody>`;
            }
        }

        /**
         * Robust CSV Parser
         * Handles:
         * - Commas inside quoted fields
         * - Escaped quotes ("" becomes ")
         * - Newlines within quoted fields
         * - Varying column counts (returns rows as-is, maxCols determined later)
         * - Empty lines
         * @param {string} csvString The raw CSV text
         * @returns {Array<Array<string>>} An array of arrays, where each inner array is a row of fields.
         */
        function parseCSVString(csvString) {
            const rows = [];
            let currentRow = [];
            let currentField = '';
            let inQuote = false;
            let i = 0;

            // Normalize line endings to LF for simpler processing
            csvString = csvString.replace(/\r\n/g, '\n').replace(/\r/g, '\n');

            while (i < csvString.length) {
                const char = csvString[i];
                const nextChar = csvString[i + 1];

                if (inQuote) {
                    if (char === '"') {
                        if (nextChar === '"') {
                            // Escaped quote: "" becomes "
                            currentField += '"';
                            i++; // Skip the next quote as it's part of the escape
                        } else {
                            // End of quoted field
                            inQuote = false;
                        }
                    } else {
                        // Character inside a quote
                        currentField += char;
                    }
                } else {
                    if (char === '"') {
                        // Start of a quoted field
                        inQuote = true;
                    } else if (char === ',') {
                        // End of a field
                        currentRow.push(currentField);
                        currentField = '';
                    } else if (char === '\n') {
                        // End of a row
                        currentRow.push(currentField);
                        if (currentRow.length > 0 || currentField.trim() !== '') { // Only add non-empty rows
                            rows.push(currentRow);
                        }
                        currentRow = [];
                        currentField = '';
                    } else {
                        // Regular character
                        currentField += char;
                    }
                }
                i++;
            }

            // Add the last field and row if not ended with a newline
            currentRow.push(currentField);
            if (currentRow.length > 0 || currentField.trim() !== '') {
                rows.push(currentRow);
            }

            // Filter out any completely empty rows that might have snuck in due to multiple newlines
            return rows.filter(row => row.some(field => field.trim() !== ''));
        }

        // Initial setup for the table
        parseCSV(); // Call once on load to set up the placeholder table
    </script>
</body>
</html>
