    <script>
        function parseCSV() {
            const csvText = document.getElementById('csvInput').value;
            const table = document.getElementById('csvTable');
            const errorMessageDiv = document.getElementById('errorMessage');
            table.innerHTML = ''; // Clear previous table data
            errorMessageDiv.innerHTML = ''; // Clear previous error messages

            if (!csvText.trim()) {
                errorMessageDiv.textContent = "Please enter some CSV data.";
                return;
            }

            try {
                const rows = [];
                let currentRow = [];
                let currentField = '';
                let inQuote = false;

                for (let i = 0; i < csvText.length; i++) {
                    const char = csvText[i];
                    const nextChar = csvText[i + 1];

                    if (inQuote) {
                        if (char === '"') {
                            if (nextChar === '"') {
                                // Escaped quote: "" -> "
                                currentField += '"';
                                i++; // Skip the next quote character
                            } else {
                                // End of quote
                                inQuote = false;
                            }
                        } else {
                            currentField += char;
                        }
                    } else {
                        if (char === '"') {
                            // Start of quote
                            inQuote = true;
                        } else if (char === ',') {
                            // End of field
                            currentRow.push(currentField);
                            currentField = '';
                        } else if (char === '\n' || char === '\r') {
                            // End of row
                            if (char === '\r' && nextChar === '\n') {
                                i++; // Handle CRLF
                            }
                            currentRow.push(currentField);
                            rows.push(currentRow);
                            currentRow = [];
                            currentField = '';
                            // Important: If we are at the end of the file and there's a trailing newline,
                            // we don't want to add an empty row.
                            // This also prevents adding an empty row if the last char is a newline.
                            if (i === csvText.length - 1 && char === '\n') {
                                // Do nothing, we've already processed the last row
                            } else if (csvText.substring(i + 1).trim() === '') {
                                // If remaining text is just whitespace, don't add an empty row
                                break;
                            }
                        } else {
                            currentField += char;
                        }
                    }
                }

                // Add the last field and row if there's any pending data
                if (currentField !== '' || currentRow.length > 0 || rows.length === 0) {
                     // Only push if there's actual data or if it's the very first row being processed
                    currentRow.push(currentField);
                    rows.push(currentRow);
                }

                // Filter out genuinely empty rows that might result from trailing newlines
                const filteredRows = rows.filter(row => row.some(field => field.trim() !== '') || row.length > 0);
                if (filteredRows.length === 0 && csvText.trim() !== '') {
                    // This case handles a single field input without a trailing newline
                    filteredRows.push(rows[0]);
                }


                if (filteredRows.length === 0) {
                    errorMessageDiv.textContent = "No valid CSV data parsed.";
                    return;
                }

                // Create table header
                const thead = table.createTHead();
                const headerRow = thead.insertRow();
                filteredRows[0].forEach(headerText => {
                    const th = document.createElement('th');
                    th.textContent = headerText;
                    headerRow.appendChild(th);
                });

                // Create table body
                const tbody = table.createTBody();
                for (let i = 1; i < filteredRows.length; i++) {
                    const dataRow = tbody.insertRow();
                    filteredRows[i].forEach(cellText => {
                        const td = dataRow.insertCell();
                        td.textContent = cellText;
                    });
                }

            } catch (e) {
                errorMessageDiv.textContent = `Error parsing CSV: ${e.message}`;
                console.error("CSV Parsing Error:", e);
            }
