            originalArray = generateRandomArray(arraySize);
            renderChart(bubbleSortChart, originalArray);
            renderChart(mergeSortChart, originalArray);
            renderChart(quickSortChart, originalArray);
            bubbleSortStepsSpan.textContent = 0;
            mergeSortStepsSpan.textContent = 0;
            quickSortStepsSpan.textContent = 0;
            startButton.disabled = false;
