                }
                container.appendChild(bar);
            });
        }

        function resetCharts() {
            bubbleSortStepsSpan.textContent = '0';
            mergeSortStepsSpan.textContent = '0';
            quickSortStepsSpan.textContent = '0';
            renderBars(bubbleSortChart, originalData);
            renderBars(mergeSortChart, originalData);
            renderBars(quickSortChart, originalData);
            isSorting = false;
            startButton.disabled = false;
            randomizeButton.disabled = false;
            dataSizeSlider.disabled = false;
        }

