            dataSizeValueSpan.textContent = dataSize;
            animationDelay = parseInt(animationSpeedSlider.value);
            animationSpeedValueSpan.textContent = animationDelay;
        }

        function initialize() {
            updateSliderValues();
            originalData = generateRandomData(dataSize);
            resetCharts();
        }

        // --- Sorting Algorithms ---

        // Bubble Sort
        async function bubbleSort(arr, chartContainer, stepsSpan) {
            const n = arr.length;
            let steps = 0;
            let currentArr = [...arr];

            for (let i = 0; i < n - 1; i++) {
                let swapped = false;
                for (let j = 0; j < n - 1 - i; j++) {
                    steps++;
                    stepsSpan.textContent = steps;
                    renderBars(chartContainer, currentArr, [j, j + 1], 'comparing');
                    await new Promise(resolve => setTimeout(resolve, animationDelay));

                    if (currentArr[j] > currentArr[j + 1]) {
                        [currentArr[j], currentArr[j + 1]] = [currentArr[j + 1], currentArr[j]];
                        swapped = true;
                        renderBars(chartContainer, currentArr, [j, j + 1], 'swapping');
                        await new Promise(resolve => setTimeout(resolve, animationDelay));
                    }
                }
                // Mark the largest element of this pass as sorted
                renderBars(chartContainer, currentArr, Array.from({ length: i + 1 }, (_, k) => n - 1 - k), 'sorted');
                if (!swapped) break; // Optimization: If no two elements were swapped, array is sorted
            }
            renderBars(chartContainer, currentArr, Array.from({ length: n }, (_, k) => k), 'sorted'); // Mark all as sorted
        }

        // Merge Sort
        async function mergeSort(arr, chartContainer, stepsSpan) {
            let steps = 0;
            let currentArr = [...arr]; // Create a copy to modify
            let tempArray = new Array(arr.length); // Auxiliary array for merging

            async function merge(low, mid, high) {
                for (let k = low; k <= high; k++) {
                    tempArray[k] = currentArr[k];
                }

                let i = low, j = mid + 1;
                for (let k = low; k <= high; k++) {
                    steps++;
                    stepsSpan.textContent = steps;

                    if (i > mid) {
                        currentArr[k] = tempArray[j++];
                    } else if (j > high) {
                        currentArr[k] = tempArray[i++];
                    } else if (tempArray[j] < tempArray[i]) {
                        currentArr[k] = tempArray[j++];
                    } else {
                        currentArr[k] = tempArray[i++];
                    }
                    renderBars(chartContainer, currentArr, Array.from({ length: high - low + 1 }, (_, idx) => low + idx), 'comparing');
                    await new Promise(resolve => setTimeout(resolve, animationDelay));
                }
            }

            async function sort(low, high) {
                if (high <= low) return;
                let mid = Math.floor(low + (high - low) / 2);
                await sort(low, mid);
                await sort(mid + 1, high);
                await merge(low, mid, high);
            }

            await sort(0, currentArr.length - 1);
            renderBars(chartContainer, currentArr, Array.from({ length: arr.length }, (_, k) => k), 'sorted'); // Mark all as sorted
        }

        // Quick Sort
        async function quickSort(arr, chartContainer, stepsSpan) {
            let steps = 0;
            let currentArr = [...arr];

            async function partition(low, high) {
                let pivot = currentArr[high];
                let i = (low - 1);

                for (let j = low; j <= high - 1; j++) {
                    steps++;
                    stepsSpan.textContent = steps;
                    renderBars(chartContainer, currentArr, [j, high], 'comparing'); // Highlight current element and pivot
                    await new Promise(resolve => setTimeout(resolve, animationDelay));

                    if (currentArr[j] < pivot) {
                        i++;
                        [currentArr[i], currentArr[j]] = [currentArr[j], currentArr[i]];
                        renderBars(chartContainer, currentArr, [i, j], 'swapping'); // Highlight swapped elements
                        await new Promise(resolve => setTimeout(resolve, animationDelay));
                    }
                }
                [currentArr[i + 1], currentArr[high]] = [currentArr[high], currentArr[i + 1]];
                renderBars(chartContainer, currentArr, [i + 1, high], 'swapping'); // Highlight pivot swap
                await new Promise(resolve => setTimeout(resolve, animationDelay));
                return i + 1;
            }

            async function sort(low, high) {
                if (low < high) {
                    let pi = await partition(low, high);
                    await sort(low, pi - 1);
                    await sort(pi + 1, high);
                }
                // Mark sorted segments after recursive calls
                if (high - low + 1 > 1) { // Only mark as sorted if it's a segment larger than 1
                   renderBars(chartContainer, currentArr, Array.from({ length: high - low + 1 }, (_, k) => low + k), 'sorted');
                   await new Promise(resolve => setTimeout(resolve, animationDelay));
                }
            }

            await sort(0, currentArr.length - 1);
            renderBars(chartContainer, currentArr, Array.from({ length: arr.length }, (_, k) => k), 'sorted'); // Final mark all as sorted
        }


        // --- Event Listeners ---
        dataSizeSlider.addEventListener('input', () => {
            if (!isSorting) {
                updateSliderValues();
                originalData = generateRandomData(dataSize);
                resetCharts();
            }
        });

