        randomizeButton.addEventListener('click', () => {
            if (!isSorting) {
                originalData = generateRandomData(dataSize);
                resetCharts();
            }
        });

        startButton.addEventListener('click', async () => {
            if (isSorting) return;
            isSorting = true;
            startButton.disabled = true;
            randomizeButton.disabled = true;
            dataSizeSlider.disabled = true;

            // Clear any previous animation frames (though not strictly needed with async/await)
            animationFrames.forEach(clearTimeout);
            animationFrames = [];

            // Reset step counters and render initial state
            resetCharts(); // This will re-render with originalData and reset steps

            // Start sorting concurrently
            const bubblePromise = bubbleSort(originalData, bubbleSortChart, bubbleSortStepsSpan);
            const mergePromise = mergeSort(originalData, mergeSortChart, mergeSortStepsSpan);
            const quickPromise = quickSort(originalData, quickSortChart, quickSortStepsSpan);

            await Promise.all([bubblePromise, mergePromise, quickPromise]);

            isSorting = false;
            startButton.disabled = false;
            randomizeButton.disabled = false;
            dataSizeSlider.disabled = false;
        });

        resetButton.addEventListener('click', () => {
            if (isSorting) {
                // In a real application, you might need to implement a way to stop ongoing async sorts
                // For this simple demo, we'll just allow reset to re-initialize
                // and assume ongoing sorts will finish or naturally stop when elements are sorted.
            }
            initialize();
        });

        // Initialize on load
        initialize();

    </script>
