        // --- Sorting Algorithms (with Visualization) ---

        async function bubbleSort(arr, container, stepsSpan) {
            let n = arr.length;
            let steps = 0;
            let localArr = [...arr]; // Work on a copy
            let sortedCount = 0;

            for (let i = 0; i < n - 1; i++) {
                for (let j = 0; j < n - 1 - i; j++) {
                    steps++;
                    stepsSpan.textContent = steps;
