                renderBars(localArr, container, [], -1, Array.from({length: sortedCount}, (_, k) => n - 1 - k)); // Mark sorted
            }
            renderBars(localArr, container, [], -1, Array.from({length: n}, (_, k) => k)); // All sorted
        }

        async function mergeSort(arr, container, stepsSpan) {
            let steps = 0;
            let localArr = [...arr]; // Work on a copy

            async function merge(left, right) {
                let resultArray = [], leftIndex = 0, rightIndex = 0;

                while (leftIndex < left.length && rightIndex < right.length) {
                    steps++;
                    stepsSpan.textContent = steps;
                    // No direct bar highlighting for merge comparisons across sub-arrays
                    if (left[leftIndex] < right[rightIndex]) {
                        resultArray.push(left[leftIndex++]);
                    } else {
                        resultArray.push(right[rightIndex++]);
                    }
                    // Visualizing the merge operation is tricky in place,
                    // so we'll re-render the whole array from the copied
                    // state to reflect the "merged" parts.
                    // This is a simplification for visual clarity.
                    // For a true in-place merge visualization, it's much more complex.
                    // For now, we update the whole array when a sub-array is "merged".
                    await new Promise(resolve => timeouts.push(setTimeout(resolve, animationSpeed / 4)));
                }

                return resultArray.concat(left.slice(leftIndex)).concat(right.slice(rightIndex));
            }

            async function sort(arraySegment) {
                if (arraySegment.length <= 1) {
                    return arraySegment;
                }

                const middle = Math.floor(arraySegment.length / 2);
                const left = arraySegment.slice(0, middle);
                const right = arraySegment.slice(middle);

                const sortedLeft = await sort(left);
                const sortedRight = await sort(right);

                const merged = await merge(sortedLeft, sortedRight);

                // Find the original indices in localArr and update them
                // This is a heuristic to update the main array display
                const startIndex = localArr.indexOf(arraySegment[0]); // This can be problematic if values are not unique
                if (startIndex !== -1 && merged.length === arraySegment.length) {
                    for (let i = 0; i < merged.length; i++) {
                        localArr[startIndex + i] = merged[i];
                    }
                    renderBars(localArr, container);
                    await new Promise(resolve => timeouts.push(setTimeout(resolve, animationSpeed)));
                }

                return merged;
            }

            await sort(localArr);
            renderBars(localArr, container, [], -1, Array.from({length: localArr.length}, (_, k) => k)); // All sorted
        }


        async function quickSort(arr, container, stepsSpan) {
            let steps = 0;
            let localArr = [...arr]; // Work on a copy

            async function partition(low, high) {
                let pivot = localArr[high];
                let i = (low - 1); // Index of smaller element

                renderBars(localArr, container, [], high); // Highlight pivot
                await new Promise(resolve => timeouts.push(setTimeout(resolve, animationSpeed)));

                for (let j = low; j <= high - 1; j++) {
                    steps++;
                    stepsSpan.textContent = steps;
                    renderBars(localArr, container, [j], high); // Highlight current element being compared
                    await new Promise(resolve => timeouts.push(setTimeout(resolve, animationSpeed / 2)));

                    if (localArr[j] < pivot) {
                        i++;
                        renderBars(localArr, container, [i, j], high, [], 'swapping'); // Highlight potential swap
                        await new Promise(resolve => timeouts.push(setTimeout(resolve, animationSpeed / 2)));
                        swap(localArr, i, j);
                        renderBars(localArr, container, [i, j], high, [], 'swapping'); // Show after swap
                        await new Promise(resolve => timeouts.push(setTimeout(resolve, animationSpeed / 2)));
                    }
                }
                renderBars(localArr, container, [i + 1, high], high, [], 'swapping'); // Highlight pivot placement
                await new Promise(resolve => timeouts.push(setTimeout(resolve, animationSpeed / 2)));
                swap(localArr, i + 1, high);
                renderBars(localArr, container, [i + 1, high], high, [], 'swapping'); // Show after swap
                await new Promise(resolve => timeouts.push(setTimeout(resolve, animationSpeed / 2)));

                return (i + 1);
            }

            async function sort(low, high) {
                if (low < high) {
                    let pi = await partition(low, high);

                    await sort(low, pi - 1);
                    await sort(pi + 1, high);
                }
                // Mark sorted segments after they are fully sorted
                for (let k = low; k <= high; k++) {
                   // This is challenging for partial sorts in QuickSort.
                   // We'll mark all sorted at the very end.
                }
            }

            await sort(0, localArr.length - 1);
            renderBars(localArr, container, [], -1, Array.from({length: localArr.length}, (_, k) => k)); // All sorted
        }


        // --- Main Control Functions ---

        async function startSorting() {
            if (running) return;
            running = true;
            enableControls(false); // Disable controls during sort

            // Create copies of the initial array for each algorithm
            const bubbleArr = [...initialArray];
            const mergeArr = [...initialArray];
            const quickArr = [...initialArray];

            // Run algorithms concurrently
            await Promise.all([
                bubbleSort(bubbleArr, bubbleSortContainer, bubbleSortStepsSpan),
                mergeSort(mergeArr, mergeSortContainer, mergeSortStepsSpan),
                quickSort(quickArr, quickSortContainer, quickSortStepsSpan)
            ]);

            running = false;
            enableControls(true); // Re-enable controls
        }

        function reset() {
