        async function updateBars(containerId, array, highlightedIndices = [], highlightClass = '', stepsId = '', steps = 0) {
            if (!sorting) return; // Stop if sorting is cancelled

            const container = document.getElementById(containerId);
            const bars = container.children;
            const maxValue = Math.max(...array);

            for (let i = 0; i < array.length; i++) {
                const bar = bars[i];
                if (!bar) continue; // Skip if bar doesn't exist (e.g., during merge sort's internal array copies)
                bar.style.height = `${(array[i] / maxValue) * 100}%`;
                bar.style.backgroundColor = ''; // Reset color

