            createBars('bubbleSortChart', originalArray);
            createBars('mergeSortChart', originalArray);
            createBars('quickSortChart', originalArray);
        }

        // --- Sorting Algorithms ---

        // Bubble Sort
        async function bubbleSort(arr, containerId, stepsId) {
            let n = arr.length;
            let steps = 0;
            let array = [...arr]; // Create a copy
            for (let i = 0; i < n - 1; i++) {
                for (let j = 0; j < n - i - 1; j++) {
                    steps++;
                    await updateBars(containerId, array, [j, j + 1], 'comparing', stepsId, steps);
                    if (!sorting) return; // Stop if cancelled

                    if (array[j] > array[j + 1]) {
                        [array[j], array[j + 1]] = [array[j + 1], array[j]];
                        steps++; // Count swap as a step
                        await updateBars(containerId, array, [j, j + 1], 'swapping', stepsId, steps);
                        if (!sorting) return; // Stop if cancelled
                    }
                }
                // Mark the largest element as sorted
                await updateBars(containerId, array, [n - 1 - i], 'sorted', stepsId, steps);
            }
            // Mark the first element as sorted if only one left
            await updateBars(containerId, array, [0], 'sorted', stepsId, steps);
            return array;
        }

        // Merge Sort
        async function mergeSort(arr, containerId, stepsId) {
            let steps = 0;
            let array = [...arr];

            async function merge(left, right) {
                let resultArray = [], leftIndex = 0, rightIndex = 0;

                while (leftIndex < left.length && rightIndex < right.length) {
                    steps++;
                    // No direct bar highlighting for comparing during merge, as it's conceptual
                    if (left[leftIndex] < right[rightIndex]) {
                        resultArray.push(left[leftIndex++]);
                    } else {
                        resultArray.push(right[rightIndex++]);
                    }
                }
                return resultArray.concat(left.slice(leftIndex)).concat(right.slice(rightIndex));
            }

            async function sort(currentArray, start, end) {
                if (currentArray.length <= 1) {
                    return currentArray;
                }

                const middle = Math.floor(currentArray.length / 2);
                const left = currentArray.slice(0, middle);
                const right = currentArray.slice(middle);

                const sortedLeft = await sort(left, start, start + middle - 1);
                const sortedRight = await sort(right, start + middle, end);

                const merged = await merge(sortedLeft, sortedRight);

                // Update the main array for visualization
                for (let i = 0; i < merged.length; i++) {
                    array[start + i] = merged[i];
                }
                steps++; // Count the merge operation as a step
                await updateBars(containerId, array, Array.from({length: merged.length}, (_, i) => start + i), 'comparing', stepsId, steps);
                if (!sorting) return; // Stop if cancelled
                return merged;
            }

            array = await sort(array, 0, array.length - 1);
            return array;
        }

        // Quick Sort
        async function quickSort(arr, containerId, stepsId) {
            let steps = 0;
            let array = [...arr];

            async function partition(low, high) {
                let pivot = array[high];
                let i = (low - 1); // Index of smaller element

                await updateBars(containerId, array, [high], 'pivot', stepsId, steps); // Highlight pivot
                if (!sorting) return;

                for (let j = low; j < high; j++) {
                    steps++;
                    await updateBars(containerId, array, [i + 1, j, high], 'comparing', stepsId, steps); // Highlight current elements & pivot
                    if (!sorting) return;

                    if (array[j] < pivot) {
                        i++;
                        [array[i], array[j]] = [array[j], array[i]];
                        steps++;
                        await updateBars(containerId, array, [i, j, high], 'swapping', stepsId, steps); // Highlight swapped & pivot
                        if (!sorting) return;
                    }
                }

                [array[i + 1], array[high]] = [array[high], array[i + 1]];
                steps++;
                await updateBars(containerId, array, [i + 1, high], 'swapping', stepsId, steps); // Highlight final pivot placement
                if (!sorting) return;

                return i + 1;
            }

            async function sort(low, high) {
                if (low < high) {
                    let pi = await partition(low, high);
                    if (!sorting) return;

                    await sort(low, pi - 1);
                    if (!sorting) return;
                    await sort(pi + 1, high);
                    if (!sorting) return;
                }
            }

            await sort(0, array.length - 1);
            return array;
        }


        // --- Event Listener ---
        document.getElementById('startButton').addEventListener('click', async () => {
            if (sorting) {
                // If sorting is in progress, allow stopping it (optional)
