            const mergeArray = [...originalArray];
            const quickArray = [...originalArray];

            // Run all sorts concurrently
            const bubblePromise = bubbleSort(bubbleArray, 'bubbleSortChart', 'bubbleSortSteps');
            const mergePromise = mergeSort(mergeArray, 'mergeSortChart', 'mergeSortSteps');
            const quickPromise = quickSort(quickArray, 'quickSortChart', 'quickSortSteps');

            await Promise.all([bubblePromise, mergePromise, quickPromise]);

            // Ensure all bars are marked as sorted at the end
            const allCharts = ['bubbleSortChart', 'mergeSortChart', 'quickSortChart'];
            for (const chartId of allCharts) {
                const container = document.getElementById(chartId);
                const bars = container.children;
                const arrayCopy = Array.from(bars).map(bar => parseFloat(bar.style.height)); // Get current heights to re-render
                await updateBars(chartId, arrayCopy, Array.from({ length: ARRAY_SIZE }, (_, i) => i), 'sorted');
            }

            sorting = false;
            document.getElementById('startButton').textContent = 'Restart Showdown';
            document.getElementById('startButton').disabled = false;

            setTimeout(() => {
                document.getElementById('finalMessage').classList.add('visible');
            }, FINAL_MESSAGE_DELAY);
        });

