        async function bubbleSort(arr, containerId, stepsSpanId) {
            const n = arr.length;
            let a = [...arr]; // Create a copy
            for (let i = 0; i < n - 1; i++) {
                for (let j = 0; j < n - i - 1; j++) {
                    await visualizeArray(containerId, a, stepsSpanId, [j, j + 1]);
                    if (a[j] > a[j + 1]) {
                        await visualizeArray(containerId, a, stepsSpanId, [], [j, j + 1]); // Show swap
                        [a[j], a[j + 1]] = [a[j + 1], a[j]];
                        await visualizeArray(containerId, a, stepsSpanId, [], [j, j + 1]); // Show result of swap
                    }
                }
                await markSorted(containerId, n - 1 - i); // Mark the largest element as sorted
            }
            await markSorted(containerId, 0); // Mark the last element (smallest) as sorted
            await markAllSorted(containerId, a);
        }

        async function selectionSort(arr, containerId, stepsSpanId) {
            const n = arr.length;
            let a = [...arr]; // Create a copy
            for (let i = 0; i < n - 1; i++) {
                let minIdx = i;
                // Highlight the current element we're placing
                await visualizeArray(containerId, a, stepsSpanId, [i]);
                for (let j = i + 1; j < n; j++) {
                    // Highlight current minimum and element being compared
                    await visualizeArray(containerId, a, stepsSpanId, [i, minIdx, j]);
                    if (a[j] < a[minIdx]) {
                        minIdx = j;
                    }
                }
                if (minIdx !== i) {
                    await visualizeArray(containerId, a, stepsSpanId, [], [i, minIdx]); // Show elements before swap
                    [a[i], a[minIdx]] = [a[minIdx], a[i]];
                    await visualizeArray(containerId, a, stepsSpanId, [], [i, minIdx]); // Show elements after swap
                }
                await markSorted(containerId, i); // Mark current element as sorted
            }
            await markSorted(containerId, n - 1); // Mark the last element as sorted
            await markAllSorted(containerId, a);
        }

        async function mergeSort(arr, containerId, stepsSpanId) {
            let a = [...arr]; // Create a copy
            await mergeSortRecursive(a, 0, a.length - 1, containerId, stepsSpanId);
            await markAllSorted(containerId, a);
        }

        async function mergeSortRecursive(arr, l, r, containerId, stepsSpanId) {
            if (l >= r) {
                return;
            }
            const m = Math.floor(l + (r - l) / 2);
            await mergeSortRecursive(arr, l, m, containerId, stepsSpanId);
            await mergeSortRecursive(arr, m + 1, r, containerId, stepsSpanId);
            await merge(arr, l, m, r, containerId, stepsSpanId);
        }

        async function merge(arr, l, m, r, containerId, stepsSpanId) {
            const n1 = m - l + 1;
            const n2 = r - m;

            const L = new Array(n1);
            const R = new Array(n2);

            for (let i = 0; i < n1; i++) {
                L[i] = arr[l + i];
            }
            for (let j = 0; j < n2; j++) {
                R[j] = arr[m + 1 + j];
            }

            let i = 0;
            let j = 0;
            let k = l;

            while (i < n1 && j < n2) {
                await visualizeArray(containerId, arr, stepsSpanId, [l + i, m + 1 + j], [k]); // Highlight elements being compared and target
                if (L[i] <= R[j]) {
                    arr[k] = L[i];
                    i++;
                } else {
                    arr[k] = R[j];
                    j++;
                }
                await visualizeArray(containerId, arr, stepsSpanId, [], [k]); // Show placement
                k++;
            }

            while (i < n1) {
                await visualizeArray(containerId, arr, stepsSpanId, [l + i], [k]);
                arr[k] = L[i];
                await visualizeArray(containerId, arr, stepsSpanId, [], [k]);
                i++;
                k++;
            }

            while (j < n2) {
                await visualizeArray(containerId, arr, stepsSpanId, [m + 1 + j], [k]);
                arr[k] = R[j];
                await visualizeArray(containerId, arr, stepsSpanId, [], [k]);
                j++;
                k++;
            }
        }


        // --- Control Functions ---

        function resetSteps() {
            document.getElementById('bubbleSortSteps').textContent = '0';
            document.getElementById('selectionSortSteps').textContent = '0';
            document.getElementById('mergeSortSteps').textContent = '0';
        }

        async function startComparison() {
            arraySize = parseInt(document.getElementById('arraySize').value);
            animationDelay = parseInt(document.getElementById('animationSpeed').value);

            if (isNaN(arraySize) || arraySize < 10 || arraySize > 200) {
                alert("Please enter a valid array size between 10 and 200.");
                return;
            }
            if (isNaN(animationDelay) || animationDelay < 10 || animationDelay > 500) {
                alert("Please enter a valid animation speed between 10 and 500 ms.");
                return;
            }

            resetSteps();
            const originalArray = generateRandomArray(arraySize);

            // Initialize bars for each visualizer
            createBars('bubbleSortBars', originalArray);
            createBars('selectionSortBars', originalArray);
            createBars('mergeSortBars', originalArray);

            // Run algorithms concurrently
            // Using Promise.all to wait for all sorting animations to complete
            await Promise.all([
                bubbleSort(originalArray, 'bubbleSortBars', 'bubbleSortSteps'),
                selectionSort(originalArray, 'selectionSortBars', 'selectionSortSteps'),
                mergeSort(originalArray, 'mergeSortBars', 'mergeSortSteps')
            ]);
        }

        // Initial setup when the page loads
        document.addEventListener('DOMContentLoaded', () => {
            // Set initial values
            document.getElementById('arraySize').value = arraySize;
            document.getElementById('animationSpeed').value = animationDelay;
            // Generate and display initial arrays without sorting
            const initialArray = generateRandomArray(arraySize);
            createBars('bubbleSortBars', initialArray);
            createBars('selectionSortBars', initialArray);
            createBars('mergeSortBars', initialArray);
        });
    </script>
</body>
</html>
