            if (isVulnerableMode) {
                // --- VULNERABLE MODE: String Concatenation (simulating SQL injection) ---
                console.log("Vulnerable Mode Search Input:", userInput);
                try {
                    // This creates a dynamic function string that can be manipulated
                    // by the user input. In a real SQL query, this would be concatenation
