                    // Example: `p => p.name.includes('${userInput}') || p.category.includes('${userInput}')`
                    // If userInput is "'); alert('XSS'); //", it becomes:
                    // `p => p.name.includes(''); alert('XSS'); //%') || p.category.includes(''); alert('XSS'); //%')`
                    // The `eval` below attempts to execute this.
                    const filterFunctionString = `p => p.name.toLowerCase().includes('${userInput.toLowerCase()}') || p.category.toLowerCase().includes('${userInput.toLowerCase()}')`;

                    // Using eval to simulate a database engine parsing and executing a dynamic query string
                    // THIS IS DANGEROUS IN REAL APPLICATIONS!
                    const dynamicFilter = eval(filterFunctionString);
