            } else {
                // --- SAFE MODE: Parameterized Query / Safe Filtering ---
                console.log("Safe Mode Search Input:", userInput);
                const searchTerm = userInput.toLowerCase(); // Treat input purely as data
                filteredProducts = products.filter(p =>
                    p.name.toLowerCase().includes(searchTerm) ||
                    p.category.toLowerCase().includes(searchTerm)
                );
            }
            displayResults(filteredProducts);
        }

        // --- Event Listeners ---
        vulnerableModeBtn.addEventListener('click', () => {
            isVulnerableMode = true;
            updateModeDisplay();
        });

        safeModeBtn.addEventListener('click', () => {
            isVulnerableMode = false;
