        searchQueryInput.addEventListener('keypress', (event) => {
            if (event.key === 'Enter') {
                performSearch();
            }
        });

        // --- Initial Setup ---
        updateModeDisplay(); // Set initial mode display
        displayResults(products); // Show all products initially
    </script>
