            { id: 9, name: "Webcam Full HD", category: "Peripherals", price: 60 },
            { id: 10, name: "Smartwatch Sport", category: "Wearables", price: 250 },
            { id: 11, name: "Tablet Pro 11", category: "Electronics", price: 700 },
            { id: 12, name: "Coffee Maker Deluxe", category: "Home Goods", price: 120 }
        ];

        function displayResults(filteredProducts) {
            const resultsDiv = document.getElementById('searchResults');
            if (filteredProducts.length === 0) {
                resultsDiv.innerHTML = '<p class="no-results">No products found matching your criteria.</p>';
