                tableHtml += `<tr><td>${product.id}</td><td>${product.name}</td><td>${product.category}</td><td>$${product.price.toFixed(2)}</td></tr>`;
            });
            tableHtml += '</tbody></table>';
            resultsDiv.innerHTML = tableHtml;
        }

        function escapeHtml(str) {
            const div = document.createElement('div');
            div.appendChild(document.createTextNode(str));
            return div.innerHTML;
        }

        function searchVulnerable() {
            const input = document.getElementById('productSearchInput').value;
            let simulatedQuery = "";
            let filteredProducts = [];

            // --- VULNERABLE LOGIC START ---
            // Simulate a SQL query using string concatenation
            // In a real backend, this would be passed to a database
            simulatedQuery = `SELECT * FROM products WHERE name = '${input}'`;
            document.getElementById('simulatedQuery').textContent = simulatedQuery;

            // Simple "parser" for demonstration (very simplified and specific to this demo)
            // This is where the "injection" happens in our mock.
            // We're looking for common injection patterns to demonstrate the vulnerability.
            if (input.includes("' OR 1=1")) {
                // Simulating an injection that bypasses the WHERE clause
                // e.g., ' OR 1=1 --
                // The database would interpret this as true, returning all products.
                filteredProducts = products;
            } else if (input.includes("' OR 'a'='a")) {
                // Another common bypass
                filteredProducts = products;
            } else if (input.includes("' UNION SELECT ")) {
                // Union attacks are harder to simulate meaningfully with simple JS array filtering,
                // but we can acknowledge the attempt.
                alert("UNION SELECT attack detected! In a real system, this could extract data from other tables.");
                filteredProducts = []; // For demo, we'll just show no results for this specific mock attack.
            }
            else {
                // Default search if no injection pattern is detected
                const searchName = input.toLowerCase();
                filteredProducts = products.filter(p => p.name.toLowerCase().includes(searchName));
            }
            // --- VULNERABLE LOGIC END ---

            displayResults(filteredProducts);
        }

        function searchSafe() {
            const input = document.getElementById('productSearchInput').value;
            let simulatedQuery = "";
            let filteredProducts = [];

            // --- SAFE LOGIC START ---
            // Simulate a parameterized SQL query
            // The '?' is a placeholder for the parameter.
            simulatedQuery = `SELECT * FROM products WHERE name = ?`;
            document.getElementById('simulatedQuery').textContent = simulatedQuery + `\n(Parameter: '${escapeHtml(input)}')`;

            // In a real system, the database driver would handle escaping 'input'
            // and treating it purely as data for the placeholder.
            // Here, we simply filter based on the literal input.
            const searchName = input.toLowerCase();
            // The input is treated as a literal string to match against the name.
            // Even if input is "' OR 1=1 --", it will look for a product named exactly that.
            filteredProducts = products.filter(p => p.name.toLowerCase().includes(searchName));
            // --- SAFE LOGIC END ---

            displayResults(filteredProducts);
        }

        // Initial display when loading
        document.addEventListener('DOMContentLoaded', () => {
            document.getElementById('simulatedQuery').textContent = "Enter a search term and click a button.";
            // Optionally, show all products initially for context
            // displayResults(products);
        });
    </script>
