                    tr.appendChild(td);
                });
                tbody.appendChild(tr);
            });
            table.appendChild(tbody);
            resultsDiv.appendChild(table);
        }

        async function searchProducts() {
            if (!db) {
                displayError("Database not initialized. Please refresh the page.");
                return;
            }
            clearError();

            const searchInput = document.getElementById('searchInput').value;
            const mode = document.querySelector('input[name="mode"]:checked').value;

            let query = '';
            let params = [];
            let results = [];
            let stmt = null;

            try {
                if (mode === 'vulnerable') {
                    // VULNERABLE MODE: String concatenation
                    query = `SELECT id, name, category, price FROM products WHERE name LIKE '%${searchInput}%';`;
                    displayQuery(query);
                    const res = db.exec(query);
                    if (res.length > 0) {
                        results = res[0].values.map(row => {
                            const obj = {};
                            res[0].columns.forEach((col, i) => obj[col] = row[i]);
                            return obj;
                        });
                    }
                } else {
                    // SAFE MODE: Parameterized query
                    query = `SELECT id, name, category, price FROM products WHERE name LIKE ?;`;
                    params = [`%${searchInput}%`];
                    displayQuery(query, params);
                    stmt = db.prepare(query);
                    stmt.bind(params);

                    while (stmt.step()) {
                        const row = stmt.getAsObject();
                        results.push(row);
                    }
                }
                renderResults(results);
            } catch (e) {
                displayError(`Database Error (${mode} mode): ${e.message}`);
                console.error("SQL Error:", e);
                document.getElementById('searchResults').innerHTML = '<p class="no-results">Error during search. Check the error message above.</p>';
            } finally {
                if (stmt) {
                    stmt.free(); // Ensure statement is freed in safe mode
                }
            }
        }

        // Initialize database when the page loads
        document.addEventListener('DOMContentLoaded', initDb);
    </script>
