                    },
                    getCurrentTheme: function() {
                        return currentTheme;
                    },
                    // Initialize theme on load
                    initialize: function() {
                        loadTheme();
                    }
                };
            }

            return {
                getInstance: function() {
                    if (!instance) {
                        instance = init();
                    }
                    return instance;
                }
            };
