            // A commonly used, but simplified, regex for email validation.
            // This pattern covers most common email formats but does not fully comply with RFCs.
            // It allows for:
            // - Local part: letters, numbers, dot, underscore, percent, plus, hyphen, single quotes
            //   (and quoted strings with various characters)
            // - Domain part: letters, numbers, dot, hyphen, and 2+ character TLD
            //   (or an IP address literal like [192.168.1.1])
            const emailRegex = new RegExp(
                /^(([^<>()[\]\\.,;:\s@"]+(\.[^<>()[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/
            );

            const validateEmail = () => {
                const email = emailInput.value.trim(); // .trim() removes leading/trailing whitespace

                // Remove previous validation classes
                emailInput.classList.remove('valid', 'invalid');

                if (email === '') {
                    // If the input is empty, don't show any border color
                    return;
                }

                if (emailRegex.test(email)) {
                    emailInput.classList.add('valid');
                } else {
                    emailInput.classList.add('invalid');
                }
            };

            // Validate on input change (real-time)
            emailInput.addEventListener('input', validateEmail);

            // Also validate when the field loses focus, in case user pastes
            emailInput.addEventListener('blur', validateEmail);
        });
