        // --- Buggy Counter Logic ---
        const buggyCounterDisplay = document.getElementById('buggyCounterDisplay');
        const buggyIncrementBtn = document.getElementById('buggyIncrementBtn');
        let buggyCounterValue = 0; // Keep a JS variable for internal state

        buggyIncrementBtn.addEventListener('click', () => {
            // Simulate reading the current value from the DOM (or a shared variable)
            // This is where the stale read happens
            const currentValue = parseInt(buggyCounterDisplay.textContent); 

            // Simulate an asynchronous operation (e.g., network request, heavy computation)
            // that takes some time before the value is actually updated.
            const delay = Math.floor(Math.random() * 200) + 50; // Random delay between 50ms and 250ms

            setTimeout(() => {
                // The "write" operation happens here, but it's based on a potentially stale "read"
                const newValue = currentValue + 1; 
                buggyCounterDisplay.textContent = newValue;
                // console.log(`Buggy: Read ${currentValue}, Wrote ${newValue}`); // Uncomment for console logs
            }, delay);
        });

        // --- Fixed Counter Logic ---
        const fixedCounterDisplay = document.getElementById('fixedCounterDisplay');
        const fixedIncrementBtn = document.getElementById('fixedIncrementBtn');
        let fixedCounterValue = 0; // Use a single source of truth for the counter state
        let isUpdatingFixed = false; // Flag to prevent concurrent updates (simple mutex)
        let pendingFixedUpdates = 0; // To handle rapid clicks gracefully without dropping them

        fixedIncrementBtn.addEventListener('click', () => {
            pendingFixedUpdates++; // Increment the count of pending updates

            // If an update is already in progress, just add to pending and return.
            // The currently running update will pick up the new state.
            if (isUpdatingFixed) {
                return;
            }

            // Start the update process
            isUpdatingFixed = true;
            processFixedUpdate();
        });

        function processFixedUpdate() {
            if (pendingFixedUpdates === 0) {
                isUpdatingFixed = false; // No more updates pending, release the lock
                return;
            }

            // Decrement pending updates, as we are now processing one
            pendingFixedUpdates--;

            // Increment the counter value immediately.
            // This ensures our internal state is always up-to-date and consistent.
            fixedCounterValue++; 

            // Simulate an asynchronous operation with a delay
            const delay = Math.floor(Math.random() * 200) + 50; // Random delay

            setTimeout(() => {
                // Update the DOM *after* the delay using the *current* authoritative state
                fixedCounterDisplay.textContent = fixedCounterValue;
                // console.log(`Fixed: Current state ${fixedCounterValue}`); // Uncomment for console logs

                // Once this update is complete, try to process the next one
                processFixedUpdate(); 
            }, delay);
        }

        // Initialize display values
        buggyCounterDisplay.textContent = buggyCounterValue;
        fixedCounterDisplay.textContent = fixedCounterValue;

    </script>
