        let fixedTaskLog = document.getElementById('fixedTaskList');
        let fixedProgressBar = document.getElementById('fixedProgressBar');
        let fixedProgressText = document.getElementById('fixedProgressText');

        function updateFixedProgressBar() {
            const completedTasks = fixedTaskStates.filter(state => state).length;
            const percentage = (completedTasks / NUM_TASKS) * 100;
            fixedProgressBar.style.width = `${percentage}%`;
            fixedProgressText.textContent = `${Math.round(percentage)}%`;
            fixedProgressBar.style.backgroundColor = percentage >= 100 ? '#5cb85c' : '#5cb85c'; // Always green when fixed
        }

        async function fixedTask(id) {
            const duration = Math.random() * (TASK_DURATION_MAX - TASK_DURATION_MIN) + TASK_DURATION_MIN;
            logFixed(`Task ${id}: Starting... (duration: ${duration.toFixed(0)}ms)`);

            await new Promise(resolve => setTimeout(resolve, duration));

            // FIX: Each task updates its *own* state in the fixedTaskStates array.
            // The overall progress is then calculated by summing up the completed states.
            // This avoids direct concurrent modification of a single global percentage variable.
            fixedTaskStates[id - 1] = true; // Mark this specific task as complete
            logFixed(`Task ${id}: Completed. Total completed tasks: ${fixedTaskStates.filter(state => state).length}`);
            updateFixedProgressBar();
        }

        function logFixed(message) {
            const li = document.createElement('li');
            li.textContent = message;
            fixedTaskLog.appendChild(li);
            fixedTaskLog.scrollTop = fixedTaskLog.scrollHeight; // Auto-scroll
        }

        function startFixedTasks() {
            fixedTaskStates.fill(false); // Reset all task states
            fixedTaskLog.innerHTML = '';
            updateFixedProgressBar();
            logFixed('Starting fixed tasks...');

            for (let i = 0; i < NUM_TASKS; i++) {
                fixedTask(i + 1);
            }
        }

        // Initial display update
        updateBuggyProgressBar();
        updateFixedProgressBar();
