            const incrementBtn = widgetDiv.querySelector('.increment-btn');
            const valueSpan = widgetDiv.querySelector('.value');
            let value = 0;

            // FIX: Define the event listener function *by name* or reference
            // so we can remove it later.
            function fixedIncrementHandler() {
                value++;
                valueSpan.textContent = value;
                console.log(`Fixed Widget ${widgetId} incremented to ${value}`);
            }

            incrementBtn.addEventListener('click', fixedIncrementHandler);

            // Store a reference to the handler function, associated with the widget's DOM element.
            // This is crucial for removal.
            fixedWidgetHandlers.set(widgetDiv, fixedIncrementHandler);

            fixedDashboard.appendChild(widgetDiv);
            updateFixedWidgetCount();
        }

        function removeFixedWidget() {
            if (fixedDashboard.lastChild) {
                const removedElement = fixedDashboard.lastChild;

                // FIX: Retrieve the stored handler and explicitly remove the event listener.
                const handler = fixedWidgetHandlers.get(removedElement);
                if (handler) {
                    removedElement.querySelector('.increment-btn').removeEventListener('click', handler);
                    fixedWidgetHandlers.delete(removedElement); // Remove reference from our tracking map
                }

                // Now that the event listener reference is gone, and no other code
                // holds a reference to `removedElement`, it can be garbage collected
                // once it's removed from the DOM.
                fixedDashboard.removeChild(removedElement);
                updateFixedWidgetCount();
            }
        }

        function resetFixedDashboard() {
            // FIX: Iterate through all children to ensure all listeners are removed.
            Array.from(fixedDashboard.children).forEach(widgetDiv => {
                const handler = fixedWidgetHandlers.get(widgetDiv);
                if (handler) {
                    widgetDiv.querySelector('.increment-btn').removeEventListener('click', handler);
                    fixedWidgetHandlers.delete(widgetDiv);
                }
            });

            while (fixedDashboard.firstChild) {
                fixedDashboard.removeChild(fixedDashboard.firstChild);
            }
            fixedWidgetIdCounter = 0;
            updateFixedWidgetCount();
        }

        function updateFixedWidgetCount() {
            fixedWidgetCountSpan.textContent = fixedDashboard.children.length;
        }

        document.getElementById('addFixedWidget').addEventListener('click', createFixedWidget);
        document.getElementById('removeFixedWidget').addEventListener('click', removeFixedWidget);
        document.getElementById('resetFixedDashboard').addEventListener('click', resetFixedDashboard);
    </script>
