            fixedComparisonSpan3.textContent = `NO (Expected <= $${(targetPriceFixedBoundaryCents / 100).toFixed(2)}, got $${(fixedTotalCents / 100).toFixed(2)})`;
            fixedComparisonSpan3.style.color = 'red';
        }

        // Add a small detail to show the raw float value for emphasis
        document.addEventListener('DOMContentLoaded', () => {
             const brokenTotalElement = document.getElementById('broken-total');
             const actualBrokenTotal = brokenTotal; // Use the raw float value
             brokenTotalElement.title = `Raw float value: ${actualBrokenTotal}`;
             brokenTotalElement.style.cursor = 'help';
             brokenTotalElement.textContent = `$${actualBrokenTotal.toFixed(2)} (Raw: ${actualBrokenTotal})`;
        });

    </script>
</body>
</html>
